23	// US-035 вҖ” creator profile. Shows TikTok + Instagram handles with their
24	// denormalized follower counts / avg views, a "Stale" chip when the latest
25	// metric_snapshot was flipped to status='stale' by the hourly cron, and an
26	// Add / Unlink flow wired to the manage-social-link edge function.
27	//
28	// Spec gap: the story AC says "Stale chip appears when metrics_stale_at is
29	// non-null", but there is no metrics_stale_at column on creator_profiles
30	// (see us_004 + the us_011 cron which flips metric_snapshots.status='stale'
31	// instead). The chip is therefore derived from
32	// metric_snapshots WHERE is_latest = true AND status = 'stale', which is
33	// the signal the cron actually produces per docs/tech-architecture.md В§16.
34	//
35	// Apify scrapes on add are deferred to US-036 (pull-to-refresh) to keep
36	// this story focused on the CRUD flow вҖ” matches the story AC wording
37	// ("small edge function").
38	
39	type SocialPlatform = Database['public']['Enums']['platform'];
40	type SocialLink = Database['public']['Tables']['social_links']['Row'];
41	type CreatorProfileRow = Database['public']['Tables']['creator_profiles']['Row'];
42	
43	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
44	const PLATFORMS: readonly SocialPlatform[] = ['tiktok', 'instagram'];
45	
46	export default function CreatorProfile() {
47	  const { user, signOut } = useAuth();
48	  const { show: showToast } = useToast();
49	
50	  const [profile, setProfile] = useState<CreatorProfileRow | null>(null);
51	  const [links, setLinks] = useState<SocialLink[]>([]);
52	  const [staleLinkIds, setStaleLinkIds] = useState<Set<string>>(new Set());
53	  const [loading, setLoading] = useState(true);
54	  const [pendingAction, setPendingAction] = useState<string | null>(null);
55	  const [sheetPlatform, setSheetPlatform] = useState<SocialPlatform | null>(null);
56	
57	  const load = useCallback(async () => {
58	    if (!user) return;
59	    setLoading(true);
60	    try {
61	      const [profileRes, linksRes, snapsRes] = await Promise.all([
62	        supabase
63	          .from('creator_profiles')
64	          .select('*')
65	          .eq('user_id', user.id)
66	          .maybeSingle(),
67	        supabase
68	          .from('social_links')
69	          .select('*')
70	          .eq('user_id', user.id)
71	          .neq('status', 'unlinked'),
72	        supabase
73	          .from('metric_snapshots')
74	          .select('social_link_id, status')
75	          .eq('is_latest', true)
76	          .eq('status', 'stale'),
77	      ]);
78	      if (profileRes.error) throw profileRes.error;
79	      if (linksRes.error) throw linksRes.error;
80	      if (snapsRes.error) throw snapsRes.error;
81	      setProfile(profileRes.data ?? null);
82	      setLinks(linksRes.data ?? []);
83	      setStaleLinkIds(new Set((snapsRes.data ?? []).map((r) => r.social_link_id)));
84	    } catch (err) {
85	      console.error('Profile load failed', err);
86	      showToast({ message: 'Could not load profile.', variant: 'error' });
87	    } finally {
88	      setLoading(false);
89	    }
90	  }, [user, showToast]);
91	
92	  useEffect(() => {
93	    void load();
94	  }, [load]);
95	
96	  const sections = useMemo(() => {
97	    return PLATFORMS.map((platform) => {
98	      const link = links.find((l) => l.platform === platform) ?? null;
99	      const isStale = link ? staleLinkIds.has(link.id) : false;
100	      return { platform, link, isStale };
101	    });
102	  }, [links, staleLinkIds]);
103	
104	  const onAdd = useCallback(
105	    async (platform: SocialPlatform, rawHandle: string) => {
106	      const handle = rawHandle.trim().replace(/^@+/, '').trim();
107	      if (!HANDLE_RE.test(handle)) {
108	        showToast({
109	          message: 'Handle must be letters, numbers, underscores, or dots.',
110	          variant: 'error',
111	        });
112	        return;
113	      }
114	      setPendingAction(`add:${platform}`);
115	      try {
116	        const { data, error } = await supabase.functions.invoke<{ social_link_id: string }>(
117	          'manage-social-link',
118	          { body: { action: 'add', platform, handle } },
119	        );
120	        if (error) {
121	          const ctx = (error as { context?: unknown }).context;
122	          if (
123	            ctx &&
124	            typeof ctx === 'object' &&
125	            'status' in ctx &&
126	            typeof (ctx as { json?: unknown }).json === 'function'
127	          ) {
128	            const res = ctx as Response;
129	            let body: { error?: string } = {};
130	            try {
131	              body = (await res.json()) as { error?: string };
132	            } catch {
133	              // non-JSON body вҖ” fall through to generic toast
134	            }
135	            if (res.status === 409 && body.error === 'ALREADY_LINKED') {
136	              showToast({
137	                message: `You already have a ${platformLabel(platform)} handle linked.`,
138	                variant: 'error',
139	              });
140	              return;
141	            }
142	            if (res.status === 409 && body.error === 'HANDLE_TAKEN') {
143	              showToast({
144	                message: 'That handle is already linked to another account.',
145	                variant: 'error',
146	              });
147	              return;
148	            }
149	          }
150	          showToast({ message: 'Could not add handle.', variant: 'error' });
151	          return;
152	        }
153	        if (!data?.social_link_id) {
154	          showToast({ message: 'Could not add handle.', variant: 'error' });
155	          return;
156	        }
157	        setSheetPlatform(null);
158	        showToast({
159	          message: `${platformLabel(platform)} handle added.`,
160	          variant: 'success',
161	        });
162	        await load();
163	      } finally {
164	        setPendingAction(null);
165	      }
166	    },
167	    [showToast, load],
168	  );
169	
170	  const onUnlink = useCallback(
171	    async (link: SocialLink) => {
172	      setPendingAction(`unlink:${link.id}`);
173	      try {
174	        const { error } = await supabase.functions.invoke('manage-social-link', {
175	          body: { action: 'unlink', social_link_id: link.id },
176	        });
177	        if (error) {
178	          showToast({ message: 'Could not unlink handle.', variant: 'error' });
179	          return;
180	        }
181	        showToast({
182	          message: `${platformLabel(link.platform)} handle unlinked.`,
183	          variant: 'success',
184	        });
185	        await load();
186	      } finally {
187	        setPendingAction(null);
188	      }
189	    },
190	    [showToast, load],
191	  );
192	
193	  return (
194	    <SafeAreaView style={styles.container}>
195	      <ScrollView contentContainerStyle={styles.scrollContent}>
196	        <View style={styles.header}>
197	          <Text style={[textStyles.display, { color: colors.ink }]}>Profile</Text>
198	          {user ? (
199	            <Text style={[textStyles.mono, styles.usernameRow]}>@{user.username}</Text>
200	          ) : null}
201	        </View>
202	
203	        {loading && profile === null ? (
204	          <View style={styles.loadingBlock}>
205	            <ActivityIndicator color={colors.ink} />
206	          </View>
207	        ) : (
208	          <View style={styles.sections}>
209	            {sections.map(({ platform, link, isStale }) => (
210	              <PlatformCard
211	                key={platform}
212	                platform={platform}
213	                link={link}
214	                profile={profile}
215	                isStale={isStale}
216	                pendingAction={pendingAction}
217	                onOpenAdd={() => setSheetPlatform(platform)}
218	                onUnlink={onUnlink}
219	              />
220	            ))}
221	          </View>
222	        )}
223	
224	        <View style={styles.signOutWrap}>
225	          <ButtonSecondary
