227	            onPress={signOut}
228	            accessibilityLabel="Sign out"
229	            testID="creator-signout"
230	          />
231	        </View>
232	      </ScrollView>
233	
234	      <AddHandleSheet
235	        platform={sheetPlatform}
236	        onDismiss={() => setSheetPlatform(null)}
237	        onSubmit={onAdd}
238	        submitting={sheetPlatform !== null && pendingAction === `add:${sheetPlatform}`}
239	      />
240	    </SafeAreaView>
241	  );
242	}
