1	// Custom JWT helper for Marketify edge functions.
2	//
3	// Contract: signJwt({ sub, role, session_id }, { ttlSeconds? }) -> compact JWT.
4	//           verifyJwt(token) -> parsed claims or throws.
5	// Algorithm: HS256 (HMAC-SHA256) via Web Crypto.
6	// Secret: MARKETIFY_JWT_SECRET env var вҖ” this is OUR signing key, deliberately
7	//         separate from Supabase's built-in JWT secret. Every `/auth/*` edge
8	//         function mints tokens here; RLS policies read `sub` and `role` via
9	//         `auth.jwt()`. `session_id` feeds the denylist lookup in В§15c.
10	// Auth:   no inbound auth requirement вҖ” this module is a building block.
11	
12	export type UserRole = "creator" | "lister";
13	
14	export interface JwtClaims {
15	  sub: string;
16	  role: UserRole;
17	  session_id: string;
18	  iat: number;
19	  exp: number;
20	}
21	
22	export interface SignInput {
23	  sub: string;
24	  role: UserRole;
25	  session_id: string;
26	}
27	
28	export interface SignOptions {
29	  ttlSeconds?: number;
30	}
31	
32	const DEFAULT_TTL_SECONDS = 7 * 24 * 60 * 60;
33	const encoder = new TextEncoder();
34	const decoder = new TextDecoder();
35	
36	function readSecret(): string {
37	  const s = Deno.env.get("MARKETIFY_JWT_SECRET");
38	  if (!s) throw new Error("MARKETIFY_JWT_SECRET is not set");
39	  return s;
40	}
41	
42	function base64UrlEncode(bytes: Uint8Array): string {
43	  let s = "";
44	  for (const b of bytes) s += String.fromCharCode(b);
45	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
46	}
47	
48	function base64UrlDecode(input: string): Uint8Array {
49	  const rem = input.length % 4;
50	  const b64 = (rem === 0 ? input : input + "=".repeat(4 - rem))
51	    .replaceAll("-", "+")
52	    .replaceAll("_", "/");
53	  let raw: string;
54	  try {
55	    raw = atob(b64);
56	  } catch {
57	    throw new Error("Malformed JWT");
58	  }
59	  const out = new Uint8Array(raw.length);
60	  for (let i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
61	  return out;
62	}
63	
64	async function importKey(
65	  secret: string,
66	  usages: KeyUsage[],
67	): Promise<CryptoKey> {
68	  return await crypto.subtle.importKey(
69	    "raw",
70	    encoder.encode(secret),
71	    { name: "HMAC", hash: "SHA-256" },
72	    false,
73	    usages,
74	  );
75	}
76	
77	export async function signJwt(
78	  input: SignInput,
79	  options: SignOptions = {},
80	): Promise<string> {
81	  const ttl = options.ttlSeconds ?? DEFAULT_TTL_SECONDS;
82	  if (!Number.isFinite(ttl) || ttl <= 0) {
83	    throw new Error("ttlSeconds must be a positive finite number");
84	  }
85	  if (input.role !== "creator" && input.role !== "lister") {
86	    throw new Error("role must be 'creator' or 'lister'");
87	  }
88	
89	  const now = Math.floor(Date.now() / 1000);
90	  const payload: JwtClaims = {
91	    sub: input.sub,
92	    role: input.role,
93	    session_id: input.session_id,
94	    iat: now,
95	    exp: now + ttl,
96	  };
97	
98	  const headerB64 = base64UrlEncode(
99	    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
100	  );
101	  const payloadB64 = base64UrlEncode(encoder.encode(JSON.stringify(payload)));
102	  const signingInput = `${headerB64}.${payloadB64}`;
103	
104	  const key = await importKey(readSecret(), ["sign"]);
105	  const sig = await crypto.subtle.sign(
106	    "HMAC",
107	    key,
108	    encoder.encode(signingInput),
109	  );
110	  const sigB64 = base64UrlEncode(new Uint8Array(sig));
111	
112	  return `${signingInput}.${sigB64}`;
113	}
114	
115	export async function verifyJwt(token: string): Promise<JwtClaims> {
116	  const parts = token.split(".");
117	  if (parts.length !== 3) throw new Error("Malformed JWT");
118	  const [headerB64, payloadB64, sigB64] = parts;
119	
120	  let header: { alg?: string };
121	  try {
122	    header = JSON.parse(decoder.decode(base64UrlDecode(headerB64)));
123	  } catch {
124	    throw new Error("Malformed JWT");
125	  }
126	  if (header.alg !== "HS256") throw new Error("Unsupported JWT algorithm");
127	
128	  const key = await importKey(readSecret(), ["verify"]);
129	  const ok = await crypto.subtle.verify(
130	    "HMAC",
131	    key,
132	    base64UrlDecode(sigB64),
133	    encoder.encode(`${headerB64}.${payloadB64}`),
134	  );
135	  if (!ok) throw new Error("Bad signature");
136	
137	  let payload: Partial<JwtClaims>;
138	  try {
139	    payload = JSON.parse(decoder.decode(base64UrlDecode(payloadB64)));
140	  } catch {
141	    throw new Error("Malformed JWT");
142	  }
143	
144	  if (
145	    typeof payload.sub !== "string" || payload.sub.length === 0 ||
146	    (payload.role !== "creator" && payload.role !== "lister") ||
147	    typeof payload.session_id !== "string" ||
148	    payload.session_id.length === 0 ||
149	    typeof payload.iat !== "number" ||
150	    typeof payload.exp !== "number"
151	  ) {
152	    throw new Error("JWT missing required claims");
153	  }
154	
155	  const now = Math.floor(Date.now() / 1000);
156	  if (payload.exp <= now) throw new Error("JWT expired");
157	  if (payload.iat > now + 60) throw new Error("JWT iat in the future");
158	
159	  return payload as JwtClaims;
160	}
